const fs = require('fs').promises;
const path = require('path');
const crypto = require('crypto');
const { createReadStream } = require('fs');
const { pipeline } = require('stream/promises');

const ALLOWED_MIME_TYPES = {
  'image/jpeg': { ext: '.jpg', maxSize: 5 * 1024 * 1024 },
  'image/png': { ext: '.png', maxSize: 5 * 1024 * 1024 },
  'image/gif': { ext: '.gif', maxSize: 5 * 1024 * 1024 },
  'application/pdf': { ext: '.pdf', maxSize: 10 * 1024 * 1024 },
  'text/plain': { ext: '.txt', maxSize: 1 * 1024 * 1024 }
};

const UPLOAD_DIR = path.resolve(__dirname, '../uploads');
const MAX_FILE_SIZE = 10 * 1024 * 1024;

const MAGIC_NUMBERS = {
  'image/jpeg': [0xFF, 0xD8, 0xFF],
  'image/png': [0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A],
  'image/gif': [0x47, 0x49, 0x46, 0x38],
  'application/pdf': [0x25, 0x50, 0x44, 0x46],
  'text/plain': null
};

async function ensureUploadDirectory() {
  try {
    await fs.access(UPLOAD_DIR);
  } catch {
    await fs.mkdir(UPLOAD_DIR, { recursive: true, mode: 0o750 });
  }
}

function generateSecureFilename(mimeType) {
  const timestamp = Date.now();
  const randomBytes = crypto.randomBytes(16).toString('hex');
  const extension = ALLOWED_MIME_TYPES[mimeType].ext;
  return `${timestamp}-${randomBytes}${extension}`;
}

async function validateMagicNumber(filePath, mimeType) {
  const magicBytes = MAGIC_NUMBERS[mimeType];
  
  if (!magicBytes) {
    return true;
  }

  const buffer = Buffer.alloc(magicBytes.length);
  const fileHandle = await fs.open(filePath, 'r');
  
  try {
    await fileHandle.read(buffer, 0, magicBytes.length, 0);
    
    for (let i = 0; i < magicBytes.length; i++) {
      if (buffer[i] !== magicBytes[i]) {
        return false;
      }
    }
    
    return true;
  } finally {
    await fileHandle.close();
  }
}

async function validateFileContent(filePath, mimeType) {
  const stats = await fs.stat(filePath);
  
  if (stats.size === 0) {
    return false;
  }

  const isValidMagic = await validateMagicNumber(filePath, mimeType);
  if (!isValidMagic) {
    return false;
  }

  if (mimeType.startsWith('image/')) {
    const content = await fs.readFile(filePath);
    const contentStr = content.toString('utf8', 0, Math.min(1024, content.length));
    
    if (contentStr.includes('<?php') || 
        contentStr.includes('<%') || 
        contentStr.includes('<script') ||
        contentStr.match(/\x00/)) {
      return false;
    }
  }

  return true;
}

function sanitizePath(filePath) {
  const normalized = path.normalize(filePath);
  const resolved = path.resolve(UPLOAD_DIR, normalized);
  
  if (!resolved.startsWith(UPLOAD_DIR)) {
    throw new Error('Path traversal detected');
  }
  
  return resolved;
}

async function handleFileUpload(file) {
  if (!file) {
    throw new Error('No file provided');
  }

  const { filepath, originalFilename, mimetype, size } = file;

  if (size > MAX_FILE_SIZE) {
    await fs.unlink(filepath).catch(() => {});
    throw new Error(`File size exceeds maximum allowed size of ${MAX_FILE_SIZE} bytes`);
  }

  if (!ALLOWED_MIME_TYPES[mimetype]) {
    await fs.unlink(filepath).catch(() => {});
    throw new Error(`File type ${mimetype} is not allowed`);
  }

  const allowedConfig = ALLOWED_MIME_TYPES[mimetype];
  if (size > allowedConfig.maxSize) {
    await fs.unlink(filepath).catch(() => {});
    throw new Error(`File size exceeds maximum allowed size for ${mimetype}`);
  }

  const isValidContent = await validateFileContent(filepath, mimetype);
  if (!isValidContent) {
    await fs.unlink(filepath).catch(() => {});
    throw new Error('File content validation failed');
  }

  await ensureUploadDirectory();

  const secureFilename = generateSecureFilename(mimetype);
  const destinationPath = sanitizePath(secureFilename);

  await fs.rename(filepath, destinationPath);
  await fs.chmod(destinationPath, 0o640);

  return {
    success: true,
    filename: secureFilename,
    originalFilename: path.basename(originalFilename),
    mimetype: mimetype,
    size: size,
    path: destinationPath
  };
}

async function handleMultipleFileUploads(files) {
  const results = [];
  const errors = [];

  for (const file of files) {
    try {
      const result = await handleFileUpload(file);
      results.push(result);
    } catch (error) {
      errors.push({
        filename: file.originalFilename,
        error: error.message
      });
      
      if (file.filepath) {
        await fs.unlink(file.filepath).catch(() => {});
      }
    }
  }

  return {
    successful: results,
    failed: errors
  };
}

